CREATE TABLE orders (
  id INT AUTO_INCREMENT PRIMARY KEY,
  customer_id INT NOT NULL,
  FOREIGN KEY (customer_id) REFERENCES customers(id)
    ON DELETE CASCADE
) ENGINE=InnoDB;

SET SESSION TRANSACTION ISOLATION LEVEL READ COMMITTED;
START TRANSACTION;
UPDATE accounts SET balance = balance - 100 WHERE id = 1;
UPDATE accounts SET balance = balance + 100 WHERE id = 2;
COMMIT;

-- Non-sargable (no index use):
SELECT * FROM orders WHERE YEAR(created_at) = 2025;
-- Sargable rewrite:
SELECT * FROM orders
WHERE created_at >= '2025-01-01'
  AND created_at <  '2026-01-01';

ALTER TABLE articles ADD FULLTEXT ft_body (title, body);
SELECT id, MATCH(title, body) AGAINST('mysql +index' IN BOOLEAN MODE) AS score
FROM articles
WHERE MATCH(title, body) AGAINST('mysql +index' IN BOOLEAN MODE);

CREATE VIEW active_customers AS
SELECT id, name, email
FROM customers
WHERE status = 'active';

SELECT * FROM active_customers WHERE email LIKE '%@corp.com';

CREATE TABLE products (
  id INT PRIMARY KEY,
  attrs JSON,
  color VARCHAR(20) AS (attrs->>'$.color') STORED,
  INDEX ix_color (color)
);
SELECT id FROM products WHERE color = 'red';
